<script lang="ts">
	import type { StoreLocation } from '$lib/types/store';

	interface StoreCardProps {
		store: StoreLocation;
		isSelected: boolean;
		onselect?: (store: StoreLocation) => void;
	}

	let { store, isSelected, onselect }: StoreCardProps = $props();

	function handleSelect() {
		if (onselect) {
			onselect(store);
		}
	}
</script>

