<style>
	.store-card {
		align-items: center;
		background-color: #ffffff;
		border: 1px solid #cccccc;
		display: flex;
		flex-direction: column;
		gap: 8px;
		padding: 16px;
		transition: all 0.25s ease-in-out;
	}

	.store-card:hover {
		background-color: #f9fafb;
	}

	.store-card.selected {
		background-color: #ffffff;
		border: 2px solid #000000;
	}

	.store-info {
		align-items: start;
		display: flex;
		flex-direction: column;
		gap: 4px;
		width: 100%;
	}

	.store-name {
		font-size: 1rem;
		font-weight: 600;
		color: #3f3f3f;
		margin: 0;
	}

	.store-address {
		font-size: 0.875rem;
		color: #696969;
		margin: 0;
	}

	.store-details {
		align-items: start;
		display: flex;
		flex-direction: row;
		gap: 8px;
		justify-content: space-between;
		width: 100%;
	}

	.store-distance,
	.store-hours {
		color: #3f3f3f;
		font-size: 0.875rem;
		margin: 0;
	}

	.store-open-status {
		color: #006618;
		font-weight: bold;
	}

	.select-button {
		align-items: center;
		background-color: #ffffff;
		border: 1px solid #cccccc;
		border-radius: 9999px;
		color: #000000;
		cursor: pointer;
		display: flex;
		font-size: 0.875rem;
		font-weight: 600;
		gap: 8px;
		padding: 6px 16px;
		transition: all 0.25s ease-in-out;
	}

	.select-button.selected {
		border-color: #000000;
	}

	.select-button:hover {
		background-color: #f2f2f2;
		border-color: #000000;
	}
</style>
